{
    solver          PBiCGStab;
    preconditioner  DILU;
    tolerance       1e-06;
    relTol          0.1;
}

k
{
    solver          smoothSolver;
    smoother        symGaussSeidel;
    nSweeps         2;
    tolerance       1e-06;
